"use client";

import Link from "next/link";
import { Menu, X } from "lucide-react";
import { useEffect, useMemo, useRef, useState } from "react";
import { usePathname } from "next/navigation";

import { CORE_MOBILE_TABS, getSidebarSections } from "@/components/app/route-meta";
import { SidebarNav } from "@/components/app/sidebar-nav";
import { useSession } from "@/components/app/session-provider";
import { useDialogA11y } from "@/components/app/use-dialog-a11y";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { cn } from "@/lib/utils";

export function MobileNav() {
  const pathname = usePathname();
  const [open, setOpen] = useState(false);
  const { status, user } = useSession();
  const openButtonRef = useRef<HTMLButtonElement>(null);
  const closeButtonRef = useRef<HTMLButtonElement>(null);
  const drawerRef = useRef<HTMLDivElement>(null);
  const mainSections = getSidebarSections("main");
  const adminSections = getSidebarSections("admin");

  const [prevPathname, setPrevPathname] = useState(pathname);

  if (pathname !== prevPathname) {
    setPrevPathname(pathname);
    setOpen(false);
  }

  useDialogA11y({
    open,
    containerRef: drawerRef,
    initialFocusRef: closeButtonRef,
    returnFocusRef: openButtonRef,
    onClose: () => setOpen(false),
  });

  const moreActive = useMemo(
    () => !CORE_MOBILE_TABS.some((route) => route.href === pathname),
    [pathname],
  );

  return (
    <>
      <div className="lg:hidden">
        <div className="pointer-events-none fixed inset-x-0 bottom-0 z-30 px-3 pb-[max(env(safe-area-inset-bottom),0.75rem)]">
          <div className="pointer-events-auto app-panel mx-auto max-w-xl p-2.5 shadow-[0_10px_30px_rgba(15,23,42,0.12)]">
            <nav aria-label="Mobile primary navigation" className="grid grid-cols-5 gap-1">
              {CORE_MOBILE_TABS.map((route) => {
                const Icon = route.icon;
                const active = pathname === route.href;
                return (
                  <Link
                    key={route.href}
                    href={route.href}
                    aria-current={active ? "page" : undefined}
                    className={cn(
                      "flex min-h-[56px] flex-col items-center justify-center rounded-lg px-1 py-2 text-xs font-medium",
                      active
                        ? "bg-[color:var(--accent)]/12 text-[color:var(--accent)]"
                        : "text-[color:var(--muted-foreground)] hover:bg-[color:var(--muted)]",
                    )}
                  >
                    <Icon className="mb-1 h-4 w-4" aria-hidden />
                    <span className="truncate">{route.label}</span>
                  </Link>
                );
              })}
              <button
                ref={openButtonRef}
                type="button"
                aria-label="Open navigation drawer"
                aria-expanded={open}
                aria-controls="mobile-nav-drawer"
                onClick={() => setOpen(true)}
                className={cn(
                  "flex min-h-[56px] flex-col items-center justify-center rounded-lg px-1 py-2 text-xs font-medium",
                  moreActive
                    ? "bg-[color:var(--accent)]/12 text-[color:var(--accent)]"
                    : "text-[color:var(--muted-foreground)] hover:bg-[color:var(--muted)]",
                )}
              >
                <Menu className="mb-1 h-4 w-4" aria-hidden />
                <span>More</span>
              </button>
            </nav>
          </div>
        </div>
      </div>

      {open ? (
        <div className="lg:hidden">
          <div className="fixed inset-0 z-40 bg-black/35" onClick={() => setOpen(false)} aria-hidden />
          <div
            id="mobile-nav-drawer"
            ref={drawerRef}
            role="dialog"
            aria-modal="true"
            aria-label="Navigation menu"
            className="fixed inset-y-0 right-0 z-50 w-[min(92vw,22rem)] border-l border-[color:var(--border)] bg-[color:var(--background)] p-4 pb-[max(env(safe-area-inset-bottom),2rem)] pt-[max(env(safe-area-inset-top),1.25rem)] shadow-[0_12px_30px_rgba(15,23,42,0.2)]"
          >
            <div className="mb-4 flex items-start justify-between gap-3">
              <div className="text-center sm:text-left">
                <div className="text-base font-semibold leading-tight">Navigation</div>
                <div className="text-xs text-[color:var(--muted-foreground)]">Primary routes and account context</div>
              </div>
              <Button
                ref={closeButtonRef}
                type="button"
                variant="secondary"
                size="sm"
                onClick={() => setOpen(false)}
                className="px-2.5"
              >
                <X className="h-4 w-4" aria-hidden />
                <span className="sr-only">Close navigation</span>
              </Button>
            </div>

            <div className="mb-4 flex flex-wrap justify-center gap-2 sm:justify-start">
              {status === "authenticated" && user ? (
                <>
                  <Badge>{user.account_role}</Badge>
                  <Badge variant="outline">{user.profile_mode}</Badge>
                </>
              ) : (
                <Badge variant="outline">{status === "loading" ? "Session loading" : "Not signed in"}</Badge>
              )}
            </div>

            <div className="space-y-4 overflow-y-auto pb-24">
              {mainSections.map((section) => (
                <SidebarNav
                  key={section.id}
                  routes={section.routes}
                  activePathname={pathname}
                  title={section.title}
                  titleId={`mobile-sidebar-${section.id}`}
                  isCollapsed={false}
                />
              ))}
              {adminSections.map((section) => (
                <SidebarNav
                  key={section.id}
                  routes={section.routes}
                  activePathname={pathname}
                  title={section.title}
                  titleId={`mobile-sidebar-${section.id}`}
                  isCollapsed={false}
                />
              ))}
            </div>
          </div>
        </div>
      ) : null}
    </>
  );
}
